/**
 * Model Tenant
 * Negocio/Tienda - Cada tenant es un negocio independiente
 */
export type Tenant = $Result.DefaultSelection<Prisma.$TenantPayload>
/**
 * Model Branch
 * Sucursal del negocio
 */
export type Branch = $Result.DefaultSelection<Prisma.$BranchPayload>
/**
 * Model User
 * Usuario del sistema (Super Admin o usuario de negocio)
 */
export type User = $Result.DefaultSelection<Prisma.$UserPayload>
/**
 * Model Supplier
 * Proveedor de productos
 */
export type Supplier = $Result.DefaultSelection<Prisma.$SupplierPayload>
/**
 * Model Category
 * Categoría de productos
 */
export type Category = $Result.DefaultSelection<Prisma.$CategoryPayload>
/**
 * Model Product
 * Producto del inventario
 */
export type Product = $Result.DefaultSelection<Prisma.$ProductPayload>
/**
 * Model ProductBatch
 * Lote específico de un producto (manejo de múltiples costos/proveedores)
 */
export type ProductBatch = $Result.DefaultSelection<Prisma.$ProductBatchPayload>
/**
 * Model ProductStock
 * Stock por sucursal
 */
export type ProductStock = $Result.DefaultSelection<Prisma.$ProductStockPayload>
/**
 * Model InventoryMovement
 * Movimientos de inventario
 */
export type InventoryMovement = $Result.DefaultSelection<Prisma.$InventoryMovementPayload>
/**
 * Model ProductPresentation
 * Presentaciones de venta de un producto (ej: Libra de un producto en KG)
 */
export type ProductPresentation = $Result.DefaultSelection<Prisma.$ProductPresentationPayload>
/**
 * Model Customer
 * Cliente del negocio
 */
export type Customer = $Result.DefaultSelection<Prisma.$CustomerPayload>
/**
 * Model Sale
 * Venta/Transacción
 */
export type Sale = $Result.DefaultSelection<Prisma.$SalePayload>
/**
 * Model SaleItem
 * Item de una venta
 */
export type SaleItem = $Result.DefaultSelection<Prisma.$SaleItemPayload>
/**
 * Model SalePayment
 * Registro de cada pago de una venta (para pagos mixtos)
 */
export type SalePayment = $Result.DefaultSelection<Prisma.$SalePaymentPayload>
/**
 * Model PurchaseOrder
 * Orden de Compra a proveedor
 */
export type PurchaseOrder = $Result.DefaultSelection<Prisma.$PurchaseOrderPayload>
/**
 * Model PurchaseOrderItem
 * Item de una orden de compra
 */
export type PurchaseOrderItem = $Result.DefaultSelection<Prisma.$PurchaseOrderItemPayload>
/**
 * Model Credit
 * Crédito/Fiado de cliente
 */
export type Credit = $Result.DefaultSelection<Prisma.$CreditPayload>
/**
 * Model CreditPayment
 * Abono a un crédito
 */
export type CreditPayment = $Result.DefaultSelection<Prisma.$CreditPaymentPayload>
/**
 * Model CashRegister
 * Caja registradora
 */
export type CashRegister = $Result.DefaultSelection<Prisma.$CashRegisterPayload>
/**
 * Model Expense
 * Gasto del negocio
 */
export type Expense = $Result.DefaultSelection<Prisma.$ExpensePayload>
/**
 * Model Notification
 * Notificación del sistema
 */
export type Notification = $Result.DefaultSelection<Prisma.$NotificationPayload>
/**
 * Model SubscriptionService
 * Servicio de suscripción (sin stock) - Gimnasios, Membresías, Streaming, etc.
 */
export type SubscriptionService = $Result.DefaultSelection<Prisma.$SubscriptionServicePayload>
/**
 * Model CustomerSubscription
 * Suscripción de cliente a un servicio
 */
export type CustomerSubscription = $Result.DefaultSelection<Prisma.$CustomerSubscriptionPayload>
/**
 * Model SubscriptionPayment
 * Pago de suscripción
 */
export type SubscriptionPayment = $Result.DefaultSelection<Prisma.$SubscriptionPaymentPayload>
/**
 * Model PointConfig
 * Configuración de puntos de fidelización por tenant
 */
export type PointConfig = $Result.DefaultSelection<Prisma.$PointConfigPayload>
/**
 * Model Coupon
 * Cupones de descuento
 */
export type Coupon = $Result.DefaultSelection<Prisma.$CouponPayload>
/**
 * Model ActivationCode
 * Códigos de activación para registro instantáneo
 */
export type ActivationCode = $Result.DefaultSelection<Prisma.$ActivationCodePayload>
/**
 * Model GiftCard
 * Tarjeta de regalo emitida por una tienda
 */
export type GiftCard = $Result.DefaultSelection<Prisma.$GiftCardPayload>
/**
 * Model GiftCardRedemption
 * Registro de cada vez que se usa una tarjeta de regalo
 */
export type GiftCardRedemption = $Result.DefaultSelection<Prisma.$GiftCardRedemptionPayload>
/**
 * Model ActivityLog
 * 
 */
export type ActivityLog = $Result.DefaultSelection<Prisma.$ActivityLogPayload>

